// Two-track smart drip decision engine
// Education track: edu_your_competitors (day 1), edu_reading_packets (day 3),
//   edu_judgment_loop (day 5), edu_integrations (day 7), edu_power_tips (day 10)
// Packet-aware track: pkt_preview, pkt_first_ready, pkt_already_waiting, setup_nudge

const EDU_SEQUENCE = [
  { key: 'edu_your_competitors', minDay: 1 },
  { key: 'edu_reading_packets', minDay: 3 },
  { key: 'edu_judgment_loop', minDay: 5 },
  { key: 'edu_integrations', minDay: 7 },
  { key: 'edu_power_tips', minDay: 10 },
];

const CONVERT_SEQUENCE = [
  { key: 'convert_week4', minDay: 28, maxDay: 30 },
  { key: 'convert_week6', minDay: 42, maxDay: 44 },
  { key: 'convert_week8', minDay: 56, maxDay: 58 },
];

const users = $input.all();
const emailsToSend = [];

for (const item of users) {
  const u = item.json;
  const sentDrips = u.sent_drips || [];
  const daysSinceSignup = parseFloat(u.days_since_signup) || 0;
  const daysSinceOnboarding = u.days_since_onboarding != null ? parseFloat(u.days_since_onboarding) : null;
  const hasPacket = u.has_packet === true || u.has_packet === 'true';
  const isMonday = parseInt(u.day_of_week) === 1;
  const onboardingDone = u.onboarding_completed_at != null;

  // Calculate days until next Monday (1=Mon, ..., 7=Sun in DOW where 0=Sun)
  const dow = parseInt(u.day_of_week); // 0=Sun, 1=Mon, ..., 6=Sat
  const daysUntilMonday = dow === 0 ? 1 : dow === 1 ? 0 : (8 - dow);

  // Track emails for this user this run (max 2: 1 packet-aware + 1 edu)
  let packetEmailSent = false;
  let eduEmailSent = false;

  // ── 1. Setup nudge (not onboarded yet) ──────────────────────────────
  if (!onboardingDone && daysSinceSignup >= 1 && !sentDrips.includes('setup_nudge')) {
    emailsToSend.push({ user_id: u.user_id, drip_key: 'setup_nudge' });
    continue; // No further drip for non-onboarded users
  }

  if (!onboardingDone) continue;

  // ── 2. Packet-aware track ───────────────────────────────────────────

  // a) First packet ready (Monday, packet exists, never sent this drip)
  if (isMonday && hasPacket && !sentDrips.includes('pkt_first_ready') && !sentDrips.includes('pkt_already_waiting')) {
    emailsToSend.push({ user_id: u.user_id, drip_key: 'pkt_first_ready' });
    packetEmailSent = true;
  }

  // b) Packet already waiting (onboarded recently, packet exists, not Monday)
  if (!packetEmailSent && !isMonday && hasPacket && daysSinceOnboarding !== null && daysSinceOnboarding <= 2
      && !sentDrips.includes('pkt_already_waiting') && !sentDrips.includes('pkt_first_ready')) {
    emailsToSend.push({ user_id: u.user_id, drip_key: 'pkt_already_waiting' });
    packetEmailSent = true;
  }

  // c) Packet preview (no packet yet, Saturday or Sunday before Monday)
  if (!packetEmailSent && !hasPacket && daysUntilMonday >= 1 && daysUntilMonday <= 2
      && !sentDrips.includes('pkt_preview') && !sentDrips.includes('pkt_first_ready') && !sentDrips.includes('pkt_already_waiting')) {
    emailsToSend.push({ user_id: u.user_id, drip_key: 'pkt_preview' });
    packetEmailSent = true;
  }

  // ── 2b. Baseline report (Day 1-3 after onboarding, snapshots exist) ──
  if (!packetEmailSent && daysSinceOnboarding !== null && daysSinceOnboarding >= 1 && daysSinceOnboarding <= 3
      && !sentDrips.includes('pkt_baseline_report') && u.has_snapshots === true) {
    emailsToSend.push({ user_id: u.user_id, drip_key: 'pkt_baseline_report' });
    packetEmailSent = true;
  }

  // ── 3. Education track (never on Monday, max 1 per day) ─────────────
  if (!isMonday && daysSinceOnboarding !== null) {
    for (const edu of EDU_SEQUENCE) {
      if (!sentDrips.includes(edu.key) && daysSinceOnboarding >= edu.minDay) {
        emailsToSend.push({ user_id: u.user_id, drip_key: edu.key });
        eduEmailSent = true;
        break; // Max 1 edu email per day
      }
    }
  }

  // ── 4. Conversion nudges (Week 4, 6, 8) ─────────────────────────────
  if (onboardingDone && daysSinceOnboarding !== null) {
    for (const conv of CONVERT_SEQUENCE) {
      if (daysSinceOnboarding >= conv.minDay && daysSinceOnboarding < conv.maxDay
          && !sentDrips.includes(conv.key)) {
        emailsToSend.push({ user_id: u.user_id, drip_key: conv.key });
        break;
      }
    }
  }
}

if (emailsToSend.length === 0) {
  return [{ json: { no_emails: true, message: 'No drip emails to send today' } }];
}

return emailsToSend.map(e => ({ json: e }));

// Log result and add delay between sends
const response = $input.first().json;
console.log(`Drip sent: ${JSON.stringify(response)}`);

// 500ms delay between sends to avoid rate limits
await new Promise(r => setTimeout(r, 500));

return [{ json: { status: 'processed', ...response } }];
